// packages/ui/src/Components/Molecules/Form/Inputs/Password/index.web.tsx
// Note: eyeIcon / eyeSlashIcon props only affect native.
// Web uses PrimeReact's built-in toggleMask eye icon.
import React from "react";
import { Password } from "primereact/password";
import type { IKitsInputPassword } from "@lmb-it/kitsconcerto-types";
import KitsContainer from "../../helpers/FormContainer";
import { useSeparator } from "../../../factory";
import { useLanguage, useComponentDefaults, useResolvedStyle } from "../../../hooks";
import { useFormInputController } from "../../helpers/useFormInputController";
import Strengthen from "./Strengthen";

const KitsInputPassword = ({ ref, ...rawProps }: IKitsInputPassword) => {
    const { mergedProps: props, themeStyle, elementStyles } = useComponentDefaults('InputPassword', rawProps, 'Input');
    const resolvedThemeStyle = useResolvedStyle(themeStyle);
    const resolvedRootStyle = useResolvedStyle(elementStyles?.root || {});

    const {
        id,
        label,
        rightAddon,
        leftAddon,
        value,
        defaultValue,
        onChange,
        errors,
        invalid,
        required,
        ignoreDirection,
        isFloatedLabel,
        promptLabel,
        weakLabel,
        mediumLabel,
        strongLabel,
        header,
        footer,
        feedback,
        toggleEye,
        disabled,
        helperText,
        inputSize,
        hideError,
        showStrengthProgress,
        schema,
        attached,
        containerStyle,
        ...rest
    } = props;

    const { isRTL } = useLanguage();

    // unified controlled/uncontrolled logic
    const { value: displayValue, emitChange } =
        useFormInputController<string>({
            value,
            defaultValue,
            onChange,
        });

    // split CSS props from native using useSeparator
    const { nativeProps } = useSeparator<HTMLInputElement>(props);

    const dirClass = isRTL && !ignoreDirection ? "text-right" : "";

    const Element = <>
        <Password
            inputRef={ref}
            className={`w-full`}
            inputClassName={`w-full ${dirClass}`}
            inputStyle={{ borderRadius: 0, border:'none', ...(resolvedRootStyle || resolvedThemeStyle) }}
            value={displayValue ?? ""}
            onChange={(e) => emitChange(e.target.value)}
            disabled={!!disabled}
            feedback={feedback}
            promptLabel={promptLabel}
            weakLabel={weakLabel}
            mediumLabel={mediumLabel}
            strongLabel={strongLabel}
            header={header}
            footer={footer}
            toggleMask={toggleEye}
            panelStyle={{ width: "100%" }}
        />

        {showStrengthProgress && schema && (
            <Strengthen
                value={displayValue ?? ""}
                show={false}
                schema={schema as any}
            />
        )}
    </>;

    if (attached) {
        return Element;
    }

    return (
        <KitsContainer
            id={id}
            helperText={helperText}
            isFloatedLabel={isFloatedLabel}
            rightAddon={rightAddon}
            leftAddon={leftAddon}
            hideError={hideError}
            required={required}
            errors={errors}
            invalid={invalid}
            label={label}
            disabled={disabled}
            inputSize={inputSize}
            containerStyle={containerStyle}
            elementStyles={elementStyles}
        >
            {Element}
        </KitsContainer>
    );
};


export default KitsInputPassword;
